import React, { useState, useEffect, useCallback } from 'react';
import { employeeAPI } from '../services/api';
import toast from 'react-hot-toast';

const TYPES = ['teaching','non_teaching','administrative'];
const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };
const MOCK = [
  { id:1, employee_id:'EMP2401', first_name:'Sunita',  last_name:'Sharma',  employee_type:'teaching',       department:'Mathematics', phone:'9000000003', basic_salary:42000, is_active:true, designation:'Senior Teacher',   joining_date:'2020-04-01' },
  { id:2, employee_id:'EMP2402', first_name:'Ramesh',  last_name:'Yadav',   employee_type:'teaching',       department:'Science',     phone:'9000000004', basic_salary:38000, is_active:true, designation:'Teacher',            joining_date:'2021-06-01' },
  { id:3, employee_id:'EMP2403', first_name:'Kavita',  last_name:'Mishra',  employee_type:'administrative', department:'Finance',     phone:'9000000005', basic_salary:35000, is_active:true, designation:'Accountant',         joining_date:'2019-04-01' },
  { id:4, employee_id:'EMP2404', first_name:'Dinesh',  last_name:'Kumar',   employee_type:'non_teaching',   department:'Transport',   phone:'9543210987', basic_salary:22000, is_active:true, designation:'Driver',             joining_date:'2022-01-15' },
  { id:5, employee_id:'EMP2405', first_name:'Anjali',  last_name:'Singh',   employee_type:'administrative', department:'Admin',       phone:'9000000006', basic_salary:28000, is_active:true, designation:'Receptionist',       joining_date:'2021-08-01' },
];
const TYPE_COLOR = { teaching:['#EDE9F8','#4C1D95'], administrative:['#DBEAFE','#1E40AF'], non_teaching:['#D1FAE5','#065F46'] };

export default function Employees() {
  const [employees, setEmployees] = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [isMock,    setIsMock]    = useState(false);
  const [total,     setTotal]     = useState(0);
  const [search,    setSearch]    = useState('');
  const [showAdd,   setShowAdd]   = useState(false);
  const [saving,    setSaving]    = useState(false);
  const [form, setForm] = useState({ firstName:'', lastName:'', type:'teaching', dept:'', designation:'', phone:'', email:'', joinDate:new Date().toISOString().split('T')[0], salary:'', qualification:'' });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await employeeAPI.getAll({ search: search||undefined, limit:50 });
      setEmployees(res.data.data||[]); setTotal(res.data.pagination?.total||0); setIsMock(false);
    } catch {
      const d = search ? MOCK.filter(e=>`${e.first_name} ${e.last_name}`.toLowerCase().includes(search.toLowerCase())||e.employee_id.includes(search)) : MOCK;
      setEmployees(d); setTotal(d.length); setIsMock(true);
    } finally { setLoading(false); }
  }, [search]);

  useEffect(() => { load(); }, [load]);

  const handleAdd = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await employeeAPI.create({ firstName:form.firstName, lastName:form.lastName, employeeType:form.type, department:form.dept, designation:form.designation, phone:form.phone, email:form.email||undefined, joiningDate:form.joinDate, basicSalary:parseInt(form.salary)||0, qualification:form.qualification||undefined });
      toast.success('✅ Employee saved to database!'); setShowAdd(false); load();
    } catch {
      const mock = { id:Date.now(), employee_id:`EMP${Date.now().toString().slice(-4)}`, first_name:form.firstName, last_name:form.lastName, employee_type:form.type, department:form.dept, phone:form.phone, basic_salary:parseInt(form.salary)||0, is_active:true, designation:form.designation, joining_date:form.joinDate };
      setEmployees(p=>[mock,...p]); toast.success('Employee added (demo mode)'); setShowAdd(false); setIsMock(true);
    } finally { setSaving(false); }
  };

  const stats = TYPES.map(t=>({ type:t, count:employees.filter(e=>e.employee_type===t).length }));

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Employees</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>
            {total} staff members
            {isMock ? <span style={{marginLeft:8,padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700}}>Demo mode</span>
                    : <span style={{marginLeft:8,padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700}}>🟢 Live DB</span>}
          </p>
        </div>
        <button onClick={()=>setShowAdd(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ Add Employee</button>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:12,marginBottom:16}}>
        {[['Total',total,'#EDE9F8','#1E1B4B'],...stats.map(s=>[s.type.replace('_',' '),s.count,TYPE_COLOR[s.type]?.[0]||'#F3F4F6',TYPE_COLOR[s.type]?.[1]||'#374151'])].map(([l,v,bg,c])=>(
          <div key={l} style={{padding:'14px',background:bg,borderRadius:12,textAlign:'center'}}>
            <div style={{fontSize:24,fontWeight:800,color:c,lineHeight:1}}>{v}</div>
            <div style={{fontSize:11,color:c,marginTop:4,fontWeight:600,textTransform:'capitalize'}}>{l}</div>
          </div>
        ))}
      </div>

      <div style={{marginBottom:12}}>
        <input placeholder="🔍 Search name, employee ID…" value={search} onChange={e=>setSearch(e.target.value)} style={{...inp,maxWidth:280}}/>
      </div>

      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Emp ID','Name','Type','Department','Designation','Phone','Salary','Status','Action'].map(h=>(
              <th key={h} style={{padding:'10px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:700,textTransform:'uppercase',borderBottom:'1px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {loading&&<tr><td colSpan={9} style={{padding:36,textAlign:'center',color:'#9CA3AF'}}>⏳ Loading…</td></tr>}
            {!loading&&employees.length===0&&<tr><td colSpan={9} style={{padding:48,textAlign:'center',color:'#9CA3AF'}}><div style={{fontSize:36,marginBottom:8}}>👥</div>No employees found</td></tr>}
            {!loading&&employees.map(e=>{
              const [bg,c] = TYPE_COLOR[e.employee_type]||['#F3F4F6','#374151'];
              return (
                <tr key={e.id} style={{borderBottom:'0.5px solid #F3F4F6',transition:'background .1s'}}
                  onMouseEnter={ev=>ev.currentTarget.style.background='#F5F3FF'}
                  onMouseLeave={ev=>ev.currentTarget.style.background=''}>
                  <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{e.employee_id}</td>
                  <td style={{padding:'10px 12px'}}>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <div style={{width:30,height:30,borderRadius:8,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:12,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{e.first_name?.[0]}</div>
                      <span style={{fontWeight:600}}>{e.first_name} {e.last_name}</span>
                    </div>
                  </td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,fontWeight:600,background:bg,color:c,textTransform:'capitalize'}}>{(e.employee_type||'').replace('_',' ')}</span></td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.department}</td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.designation}</td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.phone}</td>
                  <td style={{padding:'10px 12px',fontWeight:700}}>₹{Number(e.basic_salary||0).toLocaleString('en-IN')}</td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,fontWeight:600,background:e.is_active?'#D1FAE5':'#FEE2E2',color:e.is_active?'#065F46':'#991B1B'}}>{e.is_active?'Active':'Inactive'}</span></td>
                  <td style={{padding:'10px 12px'}}><button onClick={()=>toast(`Viewing ${e.first_name} ${e.last_name}`)} style={{padding:'4px 10px',border:'1px solid #E5E7EB',borderRadius:6,background:'#fff',fontSize:11,cursor:'pointer'}}>View</button></td>
                </tr>
              );
            })}
          </tbody>
        </table>
        <div style={{padding:'9px 14px',borderTop:'0.5px solid #E5E7EB',fontSize:11,color:'#6B7280'}}>{total} total employees</div>
      </div>

      {showAdd&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:560,maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>👤 Add Employee</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>First Name *</label><input required value={form.firstName} onChange={e=>setForm({...form,firstName:e.target.value})} style={inp} autoFocus/></div>
                <div><label style={lbl}>Last Name</label><input value={form.lastName} onChange={e=>setForm({...form,lastName:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Type *</label><select value={form.type} onChange={e=>setForm({...form,type:e.target.value})} style={inp}>{TYPES.map(t=><option key={t} value={t}>{t.replace('_',' ')}</option>)}</select></div>
                <div><label style={lbl}>Department</label><input value={form.dept} onChange={e=>setForm({...form,dept:e.target.value})} placeholder="e.g. Mathematics" style={inp}/></div>
                <div><label style={lbl}>Designation</label><input value={form.designation} onChange={e=>setForm({...form,designation:e.target.value})} placeholder="e.g. Teacher" style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Phone *</label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} maxLength={10} style={inp}/></div>
                <div><label style={lbl}>Email</label><input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:16}}>
                <div><label style={lbl}>Joining Date</label><input type="date" value={form.joinDate} onChange={e=>setForm({...form,joinDate:e.target.value})} style={inp}/></div>
                <div><label style={lbl}>Basic Salary (₹)</label><input type="number" value={form.salary} onChange={e=>setForm({...form,salary:e.target.value})} placeholder="0" style={inp}/></div>
              </div>
              <div style={{marginBottom:16}}><label style={lbl}>Qualification</label><input value={form.qualification} onChange={e=>setForm({...form,qualification:e.target.value})} placeholder="e.g. B.Ed, M.Sc" style={inp}/></div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" disabled={saving} style={{padding:'10px 22px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>{saving?'⏳ Saving…':'💾 Save Employee'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
